curAircraft.id = "{!leaseworks__Capitalized_Cost__c.Id}"; 
if('{!$Setup.leaseworks__LeaseWorksSettings__c.leaseworks__Package_Prefix__c}'== ""){
 curAircraft.Y_Hidden_Generate_Depreciation_Schedule__c=true; 
}
else{
 curAircraft.Y_Hidden_Generate_Depreciation_Schedule__c=true; 
}
